1	import {
2	    ScimError,
3	    InvalidScimPatch,
4	    InvalidScimPatchOp,
5	    NoPathInScimPatchOp,
6	    InvalidScimPatchRequest,
7	    NoTarget,
8	    RemoveValueNestedArrayNotSupported,
9	    RemoveValueNotArray,
10	    InvalidScimRemoveValue,
11	    FilterOnEmptyArray,
12	    FilterArrayTargetNotFound,
13	    InvalidRemoveOpPath
14	} from './errors/scimErrors';
15	import {
16	    ScimPatchSchema,
17	    ScimId,
18	    ScimSchema,
19	    ScimPatchOperation,
20	    ScimPatchRemoveOperation,
21	    ScimPatchAddReplaceOperation,
22	    ScimPatch,
23	    ScimResource,
24	    ScimMeta,
25	    NavigateOptions,
26	    FilterWithQueryOptions,
27	    ScimPatchOptions,
28	} from './types/types';
29	import {parse, filter} from 'scim2-parse-filter';
30	import deepEqual = require('fast-deep-equal');
31	
32	/*
33	 * Export types
34	 */
35	export {
36	    ScimPatchSchema,
37	    ScimId,
38	    ScimSchema,
39	    ScimPatchOperation,
40	    ScimPatchRemoveOperation,
41	    ScimPatchAddReplaceOperation,
42	    ScimPatch,
43	    ScimResource,
44	    ScimMeta,
45	    ScimError,
46	    InvalidScimPatch,
47	    InvalidScimPatchOp,
48	    NoPathInScimPatchOp,
49	    InvalidScimPatchRequest,
50	    NoTarget,
51	    RemoveValueNestedArrayNotSupported,
52	    RemoveValueNotArray,
53	    InvalidScimRemoveValue
54	};
55	/*
56	 * This file implement the SCIM PATCH specification.
57	 * RFC : https://tools.ietf.org/html/rfc7644#section-3.5.2
58	 * It allow to apply some patch on an existing SCIM resource.
59	 */
60	// Regex to check if this is search into array request.
61	const IS_ARRAY_SEARCH = /(\[|\])/;
62	// Regex to extract key and search request (ex: emails[primary eq true).
63	const ARRAY_SEARCH = /^(.+)\[(.+)\]$/;
64	// Split path on periods
65	const SPLIT_PERIOD = /(?!\B"[^[]*)\.(?![^\]]*"\B)/g;
66	// Valid patch operation, value needs to be in lowercase here.
67	const AUTHORIZED_OPERATION = ['remove', 'add', 'replace'];
68	
69	const CORE_SCHEMA_USER = 'urn:ietf:params:scim:schemas:core:2.0:User';
70	const CORE_SCHEMA_GROUP = 'urn:ietf:params:scim:schemas:core:2.0:Group';
71	
72	export const PATCH_OPERATION_SCHEMA = 'urn:ietf:params:scim:api:messages:2.0:PatchOp';
73	/*
74	 * PatchBodyValidation validate if the request body of the SCIM Patch is valid.
75	 * If the body is not valid the function throw an error.
76	 * @param body data from the patch request.
77	 * @throws {InvalidScimPatchRequest} if one operation is not valid.
78	 * @throws {NoPathInScimPatchOp} if one operation is a remove with no path.
79	 */
80	export function patchBodyValidation(body: ScimPatch): void {
81	    if (!body.schemas || !body.schemas.includes(PATCH_OPERATION_SCHEMA))
82	        throw new InvalidScimPatchRequest('Missing schemas.');
83	
84	    if (!Array.isArray(body.Operations))
85	        throw new InvalidScimPatchRequest('Operations should be an array.');
86	
87	    if (!body.Operations || body.Operations.length <= 0)
88	        throw new InvalidScimPatchRequest('Missing operations.');
89	
90	    body.Operations.forEach(validatePatchOperation);
91	}
92	
93	/*
94	 * This method apply patch operations on a SCIM Resource.
95	 * @param scimResource The initial resource
96	 * @param patchOperations An array of SCIM patch operations we want to apply on the scimResource object.
97	 * @param options Options to customize some behaviour of scimPatch
98	 * @return the scimResource patched.
99	 * @throws {InvalidScimPatchOp} if the patch could not happen.
100	 */
101	export function scimPatch<T extends ScimResource>(scimResource: T, patchOperations: Array<ScimPatchOperation>,
102	                                                  options: ScimPatchOptions = {mutateDocument: true, treatMissingAsAdd: true}): T {
103	    if (!options.mutateDocument) {
104	        // Deeply clone the object.
105	        // https://jsperf.com/deep-copy-vs-json-stringify-json-parse/25 (recursiveDeepCopy)
106	        scimResource = JSON.parse(JSON.stringify(scimResource));
107	    }
108	
109	    return patchOperations.reduce((patchedResource, patch) => {
110	        switch (patch.op) {
111	            case 'remove':
112	            case 'Remove':
113	                return applyRemoveOperation(patchedResource, patch);
114	            case 'add':
115	            case 'Add':
116	            case 'replace':
117	            case 'Replace':
118	                return applyAddOrReplaceOperation(patchedResource, patch, !!options.treatMissingAsAdd);
119	            default:
120	                throw new InvalidScimPatchRequest(`Operator is invalid for SCIM patch request. ${patch}`);
121	        }
122	    }, scimResource);
123	}
124	
125	/*
126	 * validateOperation is validating that the SCIM Patch Operation follow the RFC.
127	 * If not, the function throw an Error.
128	 * @param operation The SCIM operation we want to check.
129	 * @throws {InvalidScimPatchRequest} if the operation is not valid.
130	 * @throws {NoPathInScimPatchOp} if the operation is a remove with no path.
131	 */
132	function validatePatchOperation(operation: ScimPatchOperation): void {
133	    if (typeof operation.op !== 'string' || !isValidOperation(operation.op))
134	        throw new InvalidScimPatchRequest(`Invalid op "${operation.op}" in the request.`);
135	
136	    if (operation.op === 'remove' && !operation.path)
137	        throw new NoPathInScimPatchOp();
138	
139	    if (isAddOperation(operation.op) && !('value' in operation))
140	        throw new InvalidScimPatchRequest(`The operation ${operation.op} MUST contain a "value" member whose content specifies the value to be added`);
141	
142	    if (operation.path && typeof operation.path !== 'string')
143	        throw new InvalidScimPatchRequest('Path is supposed to be a string');
144	}
145	
146	function resolvePaths(path: string): string[] {
147	    const uriIndex = path.lastIndexOf(':');
148	
149	    if (uriIndex < 0) {
150	        // No schema prefix - this is a core schema path
151	        return path.split(SPLIT_PERIOD);
152	    }
153	
154	    const schemaUri = path.substring(0, uriIndex);
155	    const paths = path.substring(uriIndex +1).split(SPLIT_PERIOD);
156	    switch(schemaUri) {
157	        case CORE_SCHEMA_GROUP:
158	        case CORE_SCHEMA_USER:
159	            // Ignore core schema URIs in paths.  These are allowed but not part of object keys
160	            break;
161	        default:
162	            // Assume any other provided schema URI is an extension
163	            paths.unshift(schemaUri);
164	            break;
165	    }
166	    return paths;
167	}
168	
169	function applyRemoveOperation<T extends ScimResource>(scimResource: T, patch: ScimPatchRemoveOperation): T {
170	    // We manipulate the object directly without knowing his property, that's why we use any.
171	    let resources_scoped: Record<string, any>[];
172	    validatePatchOperation(patch);
173	
174	    // Path is supposed to be set, there are a validation in the validateOperation function.
175	    const paths = resolvePaths(patch.path);
176	
177	    try {
178	        resources_scoped = navigate(scimResource, paths, {isRemoveOp: true});
179	    } catch (error) {
180	        if (error instanceof InvalidRemoveOpPath) {
181	            return scimResource;
182	        }
183	        throw error;
184	    }
185	
186	    // Dealing with the last element of the path.
187	    const lastSubPath = paths[paths.length - 1];
188	
189	    if (!IS_ARRAY_SEARCH.test(lastSubPath)) {
190	        // This is a mono valued property
191	        for (const resource of resources_scoped) {
192	            if (!patch.value) {
193	                // No value in the remove operation, we delete it.
194	                delete resource[lastSubPath];
195	            } else {
196	                // Value in the remove operation, we remove the children by value.
197	                resource[lastSubPath] = removeWithPatchValue(resource[lastSubPath], patch.value);
198	            }
199	        }
200	        return scimResource;
201	    }
202	    for (const resource of resources_scoped) {
203	
204	        // The last element is an Array request.
205	        const {attrName, valuePath, array} = extractArray(lastSubPath, resource);
206	
207	        // We keep only items who don't match the query if supplied.
208	        resource[attrName] = filterWithQuery<any>(array, valuePath, {excludeIfMatchFilter: true});
209	
210	        // If the complex multi-valued attribute has no remaining records, the attribute SHALL be considered unassigned.
211	        if (resource[attrName].length === 0)
212	            delete resource[attrName];
213	    }
214	
215	    return scimResource;
216	}
217	
218	
219	function applyAddOrReplaceOperation<T extends ScimResource>(scimResource: T, patch: ScimPatchAddReplaceOperation, treatMissingAsAdd: boolean): T {
220	    // We manipulate the object directly without knowing his property, that's why we use any.
221	    // let resource: Record<string, any> = scimResource;
222	    let resources_scoped: Record<string, any>[];
223	    validatePatchOperation(patch);
224	
225	    if (!patch.path)
226	        return addOrReplaceAttribute(scimResource, patch);
227	
228	    // We navigate till the second to last of the path.
229	    const paths = resolvePaths(patch.path);
230	    const lastSubPath = paths[paths.length - 1];
231	
232	    try {
233	        resources_scoped = navigate(scimResource, paths);
234	    } catch(e) {
235	        if (e instanceof FilterOnEmptyArray || e instanceof FilterArrayTargetNotFound) {
236	            const resource: Record<string, any> = e.schema;
237	            // check issue https://github.com/thomaspoignant/scim-patch/issues/42 to see why we should add this
238	            const parsedPath = parse(e.valuePath);
239	            if (isAddOperation(patch.op) &&
240	              "compValue" in parsedPath &&
241	              parsedPath.compValue !== undefined &&
242	              parsedPath.op === "eq"
243	            ) {
244	                const result: any = {};
245	                result[parsedPath.attrPath] = parsedPath.compValue;
246	                result[lastSubPath] = addOrReplaceAttribute(undefined, patch, true);
247	                resource[e.attrName] = [...(resource[e.attrName] ?? []), result];
248	                return scimResource;
249	            } else if (
250	              treatMissingAsAdd &&
251	              isReplaceOperation(patch.op) &&
252	              "compValue" in parsedPath &&
253	              parsedPath.compValue !== undefined &&
254	              parsedPath.op === "eq"
255	            ) {
256	              // If the target location path specifies an attribute that does not
257	              // exist, the service provider SHALL treat the operation as an "add".
258	              return applyAddOrReplaceOperation(
259	                scimResource,
260	                { ...patch, op: "add" },
261	                false
262	              );
263	            }
264	            throw new NoTarget(patch.path);
265	        }
266	        throw e;
267	    }
268	    if (!IS_ARRAY_SEARCH.test(lastSubPath)) {
269	        for (const resource of resources_scoped) {
270	            resource[lastSubPath] = addOrReplaceAttribute(resource[lastSubPath], patch);
271	        }
272	        return scimResource;   
273	    }
274	
275	    
276	
277	    // The last element is an Array request.
278	    for (const resource of resources_scoped) {
279	        
280	        const {valuePath, array} = extractArray(lastSubPath, resource);
281	
282	        // Get the list of items who are successful for the search query.
283	        const matchFilter = filterWithQuery<any>(array, valuePath);
284	
285	        // If the target location is a multi-valued attribute for which a value selection filter ("valuePath") has been
286	        // supplied and no record match was made, the service provider SHALL indicate failure by returning HTTP status
287	        // code 400 and a "scimType" error code of "noTarget".
288	        if (isReplaceOperation(patch.op) && matchFilter.length === 0) {
289	            throw new NoTarget(patch.path);
290	        }
291	        for (let i = 0; i < array.length; i++) {
292	            // We are sure to find at least one index because matchFilter comes from array.
293	            if(matchFilter.includes(array[i])){
294	                array[i] = addOrReplaceAttribute(array[i], patch);
295	            }
296	        }
297	    }
298	
299	    return scimResource;
300	}
301	
302	/**
303	 * extractArray extract the valuePath (ex: email[primary eq true]) of a subPath
304	 * @param subPath The key we want to extract.
305	 * @param schema The object which is supposed to contains the array.
306	 * @return an array with the array name and the filter path.
307	 */
308	function extractArray(subPath: string, schema: any): ScimSearchQuery {
309	    // We extract the key of the table and what is inside [].
310	    const matchRequest = subPath.match(ARRAY_SEARCH);
311	    if (!matchRequest)
312	        throw new InvalidScimPatchOp(`This part of the path ${subPath} is invalid for SCIM patch request.`);
313	
314	    const [, attrName, valuePath] = matchRequest;
315	    const element = schema[attrName];
316	
317	    if (!Array.isArray(element))
318	        throw new FilterOnEmptyArray('Impossible to search on a mono valued attribute.', attrName, valuePath);
319	
320	    return new ScimSearchQuery(attrName, valuePath, element);
321	}
322	
323	/**
324	 * navigate allow to get the sub object who want to edit with the patch operation.
325	 * @param inputSchema the initial ScimResource
326	 * @param paths an Array who contains the path of the sub object
327	 * @param options options used while calling navigate
328	 * @return the parent object of the element we want to edit
329	 */
330	function navigate(inputSchema: any, paths: string[], options: NavigateOptions = {}): Record<string, unknown>[] {
331	    let schemas: any[] = [inputSchema];
332	    for (let i = 0; i < paths.length - 1; i++) {
333	        const subPath = paths[i];
334	
335	        // We check if the element is an array with query (ex: emails[primary eq true).
336	        if (IS_ARRAY_SEARCH.test(subPath)) {           
337	            schemas = schemas.flatMap((schema)=>{ 
338	                try {
339	                    const {attrName, valuePath, array} = extractArray(subPath, schema);
340	                    // Get the item who is successful for the search query.
341	                    const matchFilter = filterWithQuery<any>(array, valuePath);
342	                    if (matchFilter.length === 0) {
343	                        throw new FilterArrayTargetNotFound('A matching array entry was not found using the supplied filter.', attrName, valuePath, schema);
344	                    }
345	                    return matchFilter;
346	                } catch (error) {
347	                    /*
348	                        FIXME In some edge cases, not fully compliant with SCIM, this can prematurely throw en error
349	                        For example if we have a structure with multiValued complex
350	                        attribute inside of a multiValued complex attribute, in
351	                        this case this throw even if only a "branch" of the search fail.
352	                    */
353	                    if(error instanceof FilterOnEmptyArray){
354	                        error.schema = schema;
355	                    }
356	                    throw error;
357	                }
358	            });
359	        } else {
360	            schemas = schemas.flatMap((schema)=>{
361	                if (!schema[subPath] && options.isRemoveOp)
362	                    throw new InvalidRemoveOpPath();
363	
364	                return schema[subPath] || (schema[subPath] = {});
365	            });
366	        }
367	    }
368	    return schemas;
369	}
370	
371	/**
372	 * Add or Replace a property in the ScimResource
373	 * @param property The property we want to replace
374	 * @param patch The patch operation
375	 * @param multiValuedPathFilter True if thi is a multivalued path filter query
376	 * @return the patched property
377	 */
378	function addOrReplaceAttribute(property: any, patch: ScimPatchAddReplaceOperation, multiValuedPathFilter?: boolean): any {
379	    if (Array.isArray(property)) {
380	        if (Array.isArray(patch.value)) {
381	            // if we're adding an array, we need to remove duplicated values from existing array
382	            if (isAddOperation(patch.op)) {
383	                const valuesToAdd = patch.value.filter(item => !deepIncludes(property, item));
384	                return property.concat(valuesToAdd);
385	            }
386	            // else this is a replace operation
387	            return patch.value;
388	        }
389	
390	        if(isReplaceOperation(patch.op)){
391	            return property.map( 
392	                (it) => addOrReplaceAttribute(it,patch,multiValuedPathFilter)
393	            );
394	        }
395	        const a = property;
396	        if (!deepIncludes(a, patch.value))
397	            a.push(patch.value);
398	        return a;
399	    }
400	
401	    if (property !== null && typeof property === 'object') {
402	        return addOrReplaceObjectAttribute(property, patch, multiValuedPathFilter);
403	    }
404	
405	    // If the target location specifies a single-valued attribute, the existing value is replaced.
406	    return patch.value;
407	}
408	
409	/**
410	 * addOrReplaceObjectAttribute will add an attribute if it is an object
411	 * @param property The property we want to replace
412	 * @param patch The patch operation
413	 * @param multiValuedPathFilter True if thi is a multivalued path filter query
414	 */
415	function addOrReplaceObjectAttribute(property: any, patch: ScimPatchAddReplaceOperation, multiValuedPathFilter?: boolean): any {
416	    if (typeof patch.value !== 'object') {
417	        if (isAddOperation(patch.op) && !multiValuedPathFilter)
418	            throw new InvalidScimPatchOp('Invalid patch query.');
419	
420	        return patch.value;
421	    }
422	
423	    // We add all the patch values to the property object.
424	    for (const [key, value] of Object.entries(patch.value)) {
425	        assign(property, resolvePaths(key), value, patch.op);
426	    }
427	    return property;
428	}
429	
430	/**
431	 * assign is taking an array of key and add the associated nested object.
432	 * @param obj the object where we should the key
433	 * @param keyPath an array which represent the path of the nested object
434	 * @param value value to assign
435	 * @param op patch operation
436	 */
437	function assign(obj:any, keyPath:Array<string>, value:any, op: string) {
438	    const lastKeyIndex = keyPath.length-1;
439	    for (let i = 0; i < lastKeyIndex; ++ i) {
440	        const key = keyPath[i];
441	        if (!(key in obj)){
442	            obj[key] = {};
443	        }
444	        obj = obj[key];
445	    }
446	
447	    // If the attribute is an array and the operation is "add",
448	    // then the value should be added to the array
449	    const attribute = obj[keyPath[lastKeyIndex]];
450	    if (isAddOperation(op) && Array.isArray(attribute)) {
451	        // If the value is also an array, append all values of the array to the attribute
452	        if (Array.isArray(value)) {
453	            obj[keyPath[lastKeyIndex]] = [...attribute, ...value];
454	            return;
455	        }
456	
457	        // If value is not an array, simply append it as a whole to end of attribute
458	        obj[keyPath[lastKeyIndex]] = [...attribute, value];
459	        return;
460	    }
461	    obj[keyPath[lastKeyIndex]] = value;
462	}
463	
464	/**
465	 * Return the items in the array who match the filter.
466	 * @param arr the collection where we are searching.
467	 * @param querySearch the search request.
468	 * @param options options used while calling filterWithQuery
469	 * @return an array who contains the search results.
470	 */
471	function filterWithQuery<T>(arr: Array<T>, querySearch: string,
472	                            options: FilterWithQueryOptions = ({} as FilterWithQueryOptions)): Array<T> {
473	    try {
474	        const f = filter(parse(querySearch));
475	        return arr.filter(e => options.excludeIfMatchFilter ? !f(e) : f(e));
476	    } catch (error) {
477	        throw new InvalidScimPatchOp(`${error}`);
478	    }
479	}
480	
481	/**
482	 * Return the array without items supplied in .
483	 * @param arr the collection where we are searching.
484	 * @param itemsToRemove array with items to remove from original.
485	 * @return an array which contains the search results.
486	 */
487	function removeWithPatchValue<T>(arr: Array<T>, itemsToRemove: Array<T> | Record<string, any> | string | number): T[] {
488	    if (!Array.isArray(arr))
489	        throw new RemoveValueNotArray();
490	
491	    // patch value is a single item, we remove from the array all the similar items.
492	    if (!Array.isArray(itemsToRemove))
493	        return arr.filter(item => !deepEqual(itemsToRemove, item));
494	
495	    // Sometimes the patch value is an array (this is how it works with one-login, ex: [{"test":true}])
496	    // We iterate on all the values in the array to delete them all.
497	    itemsToRemove.forEach(toRemove => {
498	       if (Array.isArray(toRemove))
499	           throw new RemoveValueNestedArrayNotSupported();
500	
501	       arr = arr.filter(item => !deepEqual(toRemove, item));
502	    });
503	
504	    return arr;
505	}
506	
507	/**
508	 * deepIncludes has similar behaviour as Array.prototype.includes,
509	 * just that instead of === for equality check, it uses deepEqual library
510	 * @param array the array on which inclusion check has to be performed
511	 * @param item the item whose inclusion has to be checked
512	 * @returns true if the item is present, else false
513	 */
514	function deepIncludes(array: any[], item: any): boolean {
515	    return array.some(el => deepEqual(item, el));
516	}
517	
518	function isValidOperation(operation: string): boolean {
519	    return AUTHORIZED_OPERATION.includes(operation.toLowerCase());
520	}
521	
522	/**
523	 * isAddOperation check if the operation is an ADD
524	 * @param operation the name of the SCIM Patch operation
525	 * @return true if this is an add operation
526	 */
527	function isAddOperation(operation: string): boolean {
528	    return operation !== undefined && operation.toLowerCase() === 'add';
529	}
530	
531	/**
532	 * isReplaceOperation check if the operation is an REPLACE
533	 * @param operation the name of the SCIM Patch operation
534	 * @return true if this is a replace operation
535	 */
536	function isReplaceOperation(operation: string): boolean {
537	    return operation !== undefined && operation.toLowerCase() === 'replace';
538	}
539	
540	class ScimSearchQuery {
541	    constructor(
542	      readonly attrName: string,
543	      readonly valuePath: string,
544	      readonly array: Array<any>
545	    ) {
546	    }
547	}
