 * @param value value to assign
 * @param op patch operation
 */
function assign(obj:any, keyPath:Array<string>, value:any, op: string) {
    const lastKeyIndex = keyPath.length-1;
    for (let i = 0; i < lastKeyIndex; ++ i) {
        const key = keyPath[i];
        if (!(key in obj)){
            obj[key] = {};
        }
        obj = obj[key];
    }

